class Solution:
    def resultingString(self, s: str) -> str:
        s = list(s)
        i = 0
        while i < len(s) - 1:
            if abs(ord(s[i]) - ord(s[i+1])) == 1 or abs(ord(s[i]) - ord(s[i+1])) == 25:
                s.pop(i)
                s.pop(i)
                if i > 0:
                    i -= 1
            else:
                i += 1
        return ''.join(s)
